import { Value } from '@sinclair/typebox/value';
export const parse = (json, schema) => {
    try {
        const value = JSON.parse(typeof json === 'string' ? json : json.toString('utf8'));
        if (!Value.Check(schema, value))
            return;
        return Value.Clean(schema, value);
    }
    catch {
        return;
    }
};
